"""Builder: sinh output/scene-breakdown.md từ SRT + SCENES plan.
Mỗi scene chỉ khai báo `f` = entry SRT bắt đầu; builder tự tính span = [f .. next.f-1],
timestamp floor giây từ SRT → continuity end==start tự đảm bảo, không gap/overlap.
Project: The Coffee Can (29_COFFEE_CAN) — Cherry County, Nebraska.
KHÔNG có cột SFX (đã tách sang Bước 3 → output/sfx.json).
Shot quota mỗi thập kỷ (Rule 4.2 + KAIZEN 2026-07-15): ≥2 close-up THẬT (85mm portrait/100mm macro),
≥1 angle (low/high/over-shoulder), ≥2 wide, ≥3 medium.
"""
import re
from pathlib import Path

ROOT = Path(__file__).resolve().parent.parent
SRT = ROOT / "input" / "subtitle.srt"
TITLE = "The Dog Wouldn't Bark for Six Weeks — Then Two Strangers Walked Four Miles to His Gate"


def parse_srt():
    t = SRT.read_text(encoding="utf-8")
    ent = {}
    for b in re.split(r"\n\s*\n", t.strip()):
        ls = b.strip().split("\n")
        if len(ls) < 2:
            continue
        m = re.search(r"(\d\d):(\d\d):(\d\d),\d\d\d\s*-->\s*(\d\d):(\d\d):(\d\d),(\d\d\d)", ls[1])
        if not m:
            continue
        ent[int(ls[0])] = (
            int(m[1]) * 3600 + int(m[2]) * 60 + int(m[3]),
            int(m[4]) * 3600 + int(m[5]) * 60 + int(m[6]),
        )
    return ent


def fmt(s):
    return f"{s//3600:02d}:{s%3600//60:02d}:{s%60:02d}"


