def main():
    ent = parse_srt()
    last_entry = max(ent)
    assert SCENES[0]["f"] == 1, "scene 1 phải bắt đầu entry 1"
    for i in range(len(SCENES) - 1):
        assert SCENES[i]["f"] < SCENES[i + 1]["f"], f"boundary không tăng ở index {i} (f={SCENES[i]['f']})"
    rows = []
    for i, sc in enumerate(SCENES):
        nxt = SCENES[i + 1]["f"] - 1 if i + 1 < len(SCENES) else last_entry
        rows.append((i + 1, ent[sc["f"]][0], ent[nxt][1], sc))
    out = [f"# Scene Breakdown: {TITLE}",
           f"Total scenes: {len(rows)} | Total duration: {fmt(rows[-1][2])}", "",
           "| STT | Start | End | Dur(s) | Beat Type | Mood | Characters | Description | Visual Notes |",
           "|---|---|---|---|---|---|---|---|---|"]
    from collections import Counter
    beats = Counter()
    for stt, a, e, sc in rows:
        beats[sc["b"]] += 1
        chars = ", ".join(sc["c"]) if sc["c"] else "-"
        d = sc["d"].replace("|", "/")
        v = sc["v"].replace("|", "/")
        out.append(f"| {stt} | {fmt(a)} | {fmt(e)} | {e-a} | {sc['b']} | {sc['m']} | {chars} | {d} | {v} |")
    out += ["", "## Beat Distribution"]
    n = len(rows)
    for b in ["establishing", "dialogue", "emotional_peak", "tension", "reflection", "resolution"]:
        out.append(f"- {b}: {beats[b]} ({100*beats[b]//n}%)")
    (ROOT / "output" / "scene-breakdown.md").write_text("\n".join(out) + "\n", encoding="utf-8")
    print(f"WROTE {n} scenes, end {fmt(rows[-1][2])} ({rows[-1][2]}s)")


if __name__ == "__main__":
    main()
